import{_ as r,o as t,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const v=JSON.parse('{"title":"Creer votre compte","description":"","frontmatter":{},"headers":[],"relativePath":"fr/getting-started/create-account.md","filePath":"fr/getting-started/create-account.md"}'),i={name:"fr/getting-started/create-account.md"};function s(n,e,l,u,c,d){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="creer-votre-compte" tabindex="-1">Creer votre compte <a class="header-anchor" href="#creer-votre-compte" aria-label="Permalink to &quot;Creer votre compte&quot;">​</a></h1><p>Demarrer avec MyCompanyDesk ne prend que quelques minutes.</p><h2 id="inscription" tabindex="-1">Inscription <a class="header-anchor" href="#inscription" aria-label="Permalink to &quot;Inscription&quot;">​</a></h2><ol><li>Rendez-vous sur <a href="https://app.mycompanydesk.com" target="_blank" rel="noreferrer">app.mycompanydesk.com</a> et cliquez sur <strong>S&#39;inscrire</strong></li><li>Choisissez l&#39;une des methodes suivantes : <ul><li><strong>E-mail et mot de passe</strong> -- Entrez votre nom, votre e-mail et un mot de passe securise</li><li><strong>Google</strong> -- Connectez-vous avec votre compte Google</li><li><strong>Microsoft/Outlook</strong> -- Connectez-vous avec votre compte Microsoft</li></ul></li><li>Si vous vous etes inscrit par e-mail, verifiez votre boite de reception pour trouver un <strong>e-mail de verification</strong> et cliquez sur le lien pour verifier votre compte</li></ol><h2 id="creer-ou-rejoindre-un-espace-de-travail" tabindex="-1">Creer ou rejoindre un espace de travail <a class="header-anchor" href="#creer-ou-rejoindre-un-espace-de-travail" aria-label="Permalink to &quot;Creer ou rejoindre un espace de travail&quot;">​</a></h2><p>Apres votre inscription, vous avez deux options :</p><h3 id="creer-un-nouvel-espace-de-travail" tabindex="-1">Creer un nouvel espace de travail <a class="header-anchor" href="#creer-un-nouvel-espace-de-travail" aria-label="Permalink to &quot;Creer un nouvel espace de travail&quot;">​</a></h3><p>Si vous etes la premiere personne de votre entreprise, creez un nouvel espace de travail :</p><ol><li>Entrez le <strong>nom de votre entreprise</strong></li><li>Choisissez votre <strong>langue</strong> preferee</li><li>Cliquez sur <strong>Creer l&#39;espace de travail</strong></li></ol><p>Cela cree un espace de travail vierge ou vous pouvez commencer a ajouter les informations de votre entreprise, vos clients et vos factures.</p><h3 id="rejoindre-un-espace-de-travail-existant" tabindex="-1">Rejoindre un espace de travail existant <a class="header-anchor" href="#rejoindre-un-espace-de-travail-existant" aria-label="Permalink to &quot;Rejoindre un espace de travail existant&quot;">​</a></h3><p>Si un collegue a deja configure un espace de travail :</p><ol><li>Demandez-lui de vous envoyer une <strong>invitation</strong> depuis Parametres &gt; Equipe</li><li>Cliquez sur le lien d&#39;invitation dans votre e-mail</li><li>Acceptez l&#39;invitation pour rejoindre leur espace de travail</li></ol><p>Vous pouvez etre membre de plusieurs espaces de travail et passer de l&#39;un a l&#39;autre depuis le menu de votre compte.</p><h2 id="choisir-votre-profil-de-tableau-de-bord" tabindex="-1">Choisir votre profil de tableau de bord <a class="header-anchor" href="#choisir-votre-profil-de-tableau-de-bord" aria-label="Permalink to &quot;Choisir votre profil de tableau de bord&quot;">​</a></h2><p>Lors de votre premiere connexion, vous verrez la <strong>carte d&#39;accueil</strong> sur votre tableau de bord. MyCompanyDesk propose des profils de tableau de bord adaptes a differents roles :</p><ul><li><strong>Proprietaire / Directeur</strong> -- Vue d&#39;ensemble financiere et tresorerie</li><li><strong>Comptable / Expert-comptable</strong> -- Conformite TVA, pistes d&#39;audit, verrouillage des periodes</li><li><strong>Freelance</strong> -- Vue simplifiee axee sur la facturation et les revenus</li><li><strong>Base sur les projets</strong> -- Rentabilite des projets et suivi du temps</li><li><strong>CC (Facturation)</strong> -- Indicateurs de facturation et suivi des paiements</li><li><strong>CF (Achats)</strong> -- Suivi des depenses et gestion des fournisseurs</li><li><strong>Conformite TVA</strong> -- Calculs et echeances TVA</li><li><strong>Croissance / Operations</strong> -- Tendances de revenus et acquisition de clients</li></ul><p>Vous pouvez changer votre profil de tableau de bord a tout moment depuis les parametres du tableau de bord.</p><h2 id="completer-la-liste-de-demarrage" tabindex="-1">Completer la liste de demarrage <a class="header-anchor" href="#completer-la-liste-de-demarrage" aria-label="Permalink to &quot;Completer la liste de demarrage&quot;">​</a></h2><p>La carte d&#39;accueil vous guide a travers trois etapes cles de configuration :</p><ol><li><strong>Configurer les informations de votre entreprise</strong> -- Ajoutez le nom de votre entreprise, l&#39;adresse, le numero de TVA et les coordonnees bancaires</li><li><strong>Ajouter votre premier client</strong> -- Creez une fiche client pour commencer a facturer</li><li><strong>Creer votre premiere facture</strong> -- Envoyez votre premiere facture professionnelle</li></ol><p>La carte disparait automatiquement une fois ces etapes terminees, ou vous pouvez la fermer manuellement.</p><h2 id="prochaines-etapes" tabindex="-1">Prochaines etapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines etapes&quot;">​</a></h2><p>Maintenant que votre compte est pret, <a href="/fr/getting-started/company-setup">configurez les informations de votre entreprise</a>.</p>',24)])])}const m=r(i,[["render",s]]);export{v as __pageData,m as default};
